class Solution {
public:
    long long minSumSquareDiff(vector<int>& nums1, vector<int>& nums2, int k1, int k2) {
        int n = nums1.size();
        vector<int> diff(n);
        for (int i = 0; i < n; ++i) diff[i] = abs(nums1[i] - nums2[i]);

        long long total = 0;
        for (int d : diff) total += d;
        long long k = (long long)k1 + k2;
        if (total <= k) return 0;

        sort(diff.begin(), diff.end(), greater<int>());

        long long left = 0, right = *max_element(diff.begin(), diff.end());
        while (left < right) {
            long long mid = left + (right - left) / 2;
            long long need = 0;
            for (int d : diff) {
                if (d > mid) need += d - mid;
                else break;
            }
            if (need <= k) right = mid;
            else left = mid + 1;
        }

        long long res = 0;
        long long rem = k;
        for (int d : diff) {
            if (d > left) {
                rem -= d - left;
                res += left * left;
            } else {
                res += (long long)d * d;
            }
        }
        res -= rem * (2 * left - 1);
        return res;
    }
};
```
efficiency: HIGH
time complexity: O(n log n)
space complexity: O(n)
energy implications: LOW
explanation: Compute absolute differences, sort descending, binary-search the largest value after optimally using all k1+k2 moves to flatten the differences. The binary search counts how many moves are needed to reduce all differences above a threshold to that threshold; the residual moves are spent reducing the threshold by one more unit for some elements.

